/// <summary>
///
/// </summary>
/// <param name="_sender"></param>
/// <param name="_eventArgs"></param>
[DataEventHandler(tableStr(LedgerJournalTrans), DataEventType::PostedLoad)]
public static void LedgerJournalTrans_onPostedLoad(Common _sender, DataEventArgs _eventArgs)
{
    LedgerJournalTrans ledgerJournalTrans = _sender as LedgerJournalTrans;
    LedgerJournalTrans_Asset ledgerJournalTrans_Asset;
    str txt;

    if(curExt() == "E016")
    {
        select * from ledgerJournalTrans_Asset where ledgerJournalTrans_Asset.RefRecId == ledgerJournalTrans.RecId;

        txt = "";

        if(ledgerJournalTrans_Asset.TransType == AssetTransTypeJournal::Depreciation)
        {
            txt = strFmt("Depreciation - %1",LedgerDimensionFacade::getDisplayValueForLedgerDimension(ledgerJournalTrans.LedgerDimension));
            ledgerJournalTrans.Txt = txt;
        }

    }
}
